[CmdletBinding()]
param(
    [Parameter(Mandatory=$true)][string]$Manifest,
    [Parameter(Mandatory=$true)][string]$OutputDirectory,
    [string[]]$Pages=@('operations-dashboard','my-work','case-initiation','case-workspace','reports'),
    [ValidateSet('populated','empty','validation-error','long-content','sla-breached','read-only')][string]$State='populated'
)
$ErrorActionPreference='Stop'
$ux=Get-Content -Raw -LiteralPath (Resolve-Path -LiteralPath $Manifest) | ConvertFrom-Json
$destination=[IO.Path]::GetFullPath($OutputDirectory)
if(-not(Test-Path -LiteralPath $destination)){New-Item -ItemType Directory -Path $destination|Out-Null}
function E([object]$value){[Net.WebUtility]::HtmlEncode([string]$value)}
function Page([string]$id){@($ux.pages|Where-Object id -eq $id)|Select-Object -First 1}
function Nav([string]$active){(@($ux.shell.navigation)|ForEach-Object{$activeClass=if($_.target -eq $active){' active'}else{''};"<a class='nav$activeClass' href='$([Net.WebUtility]::HtmlEncode($_.target)).html'><span class='nav-dot' aria-hidden='true'></span><span>$(E $_.label)</span></a>"}) -join "`n"}
function Status([string]$label,[string]$tone){"<span class='status $tone'><span aria-hidden='true'>●</span>$(E $label)</span>"}
function Shell([string]$pageId,[string]$title,[string]$body,[string]$primary='New case'){
    $navigation=Nav $pageId
    $primaryButton=if([string]::IsNullOrWhiteSpace($primary)){''}else{"<a class='button primary global-create' href='case-initiation.html'>+ $(E $primary)</a>"}
@"
<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>$(E $title)</title>
<style>
:root{--nav:#142a43;--nav-dark:#0c1d30;--ink:#17263a;--muted:#607086;--line:#dce4ec;--canvas:#f4f6f9;--surface:#fff;--brand:#176b87;--brand2:#2f8ca5;--good:#24745a;--warn:#9a5b00;--bad:#b42318;--info:#235f9b;--radius:12px;--shadow:0 2px 9px rgba(23,38,58,.08)}*{box-sizing:border-box}html,body{max-width:100%;overflow-x:hidden}body{margin:0;background:var(--canvas);color:var(--ink);font:14px/1.45 "Segoe UI",Arial,sans-serif;overflow-wrap:anywhere}a{color:inherit}.skip{position:absolute;left:-9999px}.skip:focus{left:12px;top:12px;z-index:99;background:#fff;padding:10px}.shell{min-height:100vh;display:grid;grid-template-columns:248px minmax(0,1fr)}aside{height:100vh;position:sticky;top:0;background:linear-gradient(180deg,var(--nav),var(--nav-dark));padding:22px 16px;color:#fff}.brand{display:flex;align-items:center;gap:11px;padding:0 10px 22px;font-size:18px;font-weight:750}.brand-mark{width:34px;height:34px;border-radius:9px;display:grid;place-items:center;background:#38a5bd}.nav{display:flex;gap:11px;align-items:center;text-decoration:none;color:#dce7f1;padding:10px 12px;border-radius:8px;margin:3px 0}.nav.active,.nav:hover{background:rgba(255,255,255,.12);color:#fff}.nav-dot{width:16px;height:16px;border:1.5px solid currentColor;border-radius:5px}.main,.card,.split>*,.grid>*{min-width:0}.top{height:70px;position:sticky;top:0;z-index:4;display:flex;align-items:center;gap:12px;padding:0 26px;background:#fff;border-bottom:1px solid var(--line)}.search{width:min(620px,60%);padding:10px 13px;border:1px solid #becbd7;border-radius:8px;background:#fbfcfd}.avatar{width:36px;height:36px;border-radius:50%;display:grid;place-items:center;background:#d9edf2;color:var(--brand);font-weight:700}.button{display:inline-flex;align-items:center;justify-content:center;min-height:38px;padding:8px 14px;border:1px solid #b8c5d1;border-radius:8px;text-decoration:none;background:#fff;font-weight:650}.button.primary{background:var(--brand);border-color:var(--brand);color:#fff}.button.danger{border-color:#e4aaa5;color:var(--bad)}.global-create{margin-left:auto}.content{max-width:1580px;margin:auto;padding:26px}.page-head{display:flex;align-items:end;justify-content:space-between;gap:18px;margin-bottom:18px}.page-head h1{font-size:28px;line-height:1.15;margin:0 0 4px}.page-head p,.muted{color:var(--muted)}.toolbar,.actions{display:flex;gap:8px;align-items:center;flex-wrap:wrap}.card{background:var(--surface);border:1px solid var(--line);border-radius:var(--radius);box-shadow:var(--shadow)}.card-head{display:flex;align-items:center;justify-content:space-between;gap:12px;padding:16px 18px;border-bottom:1px solid var(--line)}.card-head h2,.card h2{font-size:17px;margin:0}.pad{padding:18px}.grid{display:grid;gap:15px}.cols-4{grid-template-columns:repeat(4,minmax(0,1fr))}.cols-3{grid-template-columns:repeat(3,minmax(0,1fr))}.cols-2{grid-template-columns:repeat(2,minmax(0,1fr))}.kpi{padding:17px}.kpi label{font-size:12px;color:var(--muted);font-weight:700}.value{font-size:30px;font-weight:750;margin-top:5px}.status{display:inline-flex;align-items:center;gap:5px;border-radius:99px;padding:4px 8px;font-size:11px;font-weight:700}.positive{color:var(--good);background:#e8f5ef}.warning{color:var(--warn);background:#fff4df}.critical{color:var(--bad);background:#ffefed}.neutral{color:#53657a;background:#eef2f6}.info{color:var(--info);background:#eaf2fb}.split{display:grid;grid-template-columns:minmax(0,1fr) 340px;gap:15px}.workspace-head{padding:18px;position:sticky;top:84px;z-index:2}.case-title{display:flex;justify-content:space-between;gap:18px}.case-title h1{font-size:23px;margin:3px 0}.eyebrow{text-transform:uppercase;letter-spacing:.06em;color:var(--muted);font-size:11px;font-weight:750}.meta{display:flex;gap:18px;flex-wrap:wrap;margin-top:12px}.meta div{min-width:100px}.meta b{display:block;font-size:12px}.life{display:grid;grid-template-columns:repeat(8,1fr);gap:4px;margin-top:18px}.stage{position:relative;text-align:center;color:var(--muted);font-size:11px}.stage:before{content:"";display:block;height:7px;margin-bottom:7px;border-radius:5px;background:#dbe3ea}.stage.done:before{background:var(--good)}.stage.current{font-weight:750;color:var(--brand)}.stage.current:before{background:var(--brand)}.tabs{display:flex;gap:2px;overflow:auto;border-bottom:1px solid var(--line);background:#fff}.tab{padding:11px 14px;white-space:nowrap;text-decoration:none;border-bottom:3px solid transparent}.tab.active{border-color:var(--brand);color:var(--brand);font-weight:700}.timeline{list-style:none;padding:0;margin:0}.timeline li{position:relative;padding:0 0 18px 28px;border-left:2px solid #dce4ec;margin-left:6px}.timeline li:before{content:"";position:absolute;left:-6px;top:3px;width:10px;height:10px;border-radius:50%;background:var(--brand)}.timeline li:last-child{border-left-color:transparent}.timeline time{display:block;color:var(--muted);font-size:11px}.action-panel{position:sticky;top:235px}.action-panel .button{width:100%;margin-top:8px}.callout{border-left:4px solid var(--info);background:#edf5fc;padding:12px 14px;border-radius:7px}.callout.error{border-color:var(--bad);background:#fff0ee;color:#7b1d16}.stepper{display:grid;grid-template-columns:repeat(5,1fr);gap:6px;margin:4px 0 20px}.step{font-size:12px;text-align:center;color:var(--muted)}.step:before{content:"";display:block;height:6px;background:#dbe3ea;border-radius:4px;margin-bottom:7px}.step.done:before{background:var(--good)}.step.current{font-weight:750;color:var(--brand)}.step.current:before{background:var(--brand)}.form-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:15px}.field label{display:block;font-size:12px;font-weight:700;margin-bottom:5px}.required:after{content:" *";color:var(--bad)}input,select,textarea{font:inherit;width:100%;border:1px solid #b9c6d2;border-radius:7px;padding:10px 11px;background:#fff}textarea{min-height:90px;resize:vertical}.invalid{border-color:var(--bad);box-shadow:0 0 0 2px #ffe0dd}.error-text{font-size:11px;color:var(--bad);margin-top:4px}.review{display:grid;grid-template-columns:150px 1fr;gap:8px 15px}.review dt{color:var(--muted)}.review dd{margin:0;font-weight:600}.table-wrap{overflow:auto}table{width:100%;border-collapse:collapse;min-width:720px}th,td{padding:12px 14px;border-bottom:1px solid #e7edf2;text-align:left;vertical-align:top}th{font-size:11px;text-transform:uppercase;letter-spacing:.04em;color:var(--muted);background:#f8fafc}.empty{text-align:center;padding:44px 20px;color:var(--muted)}.report{padding:18px}.report h2{margin:0 0 5px}.report a{color:var(--brand);font-weight:700}.chart-bars{height:180px;display:flex;align-items:end;gap:10px;border-bottom:1px solid #c9d4de;padding:10px}.chart-bars i{display:block;flex:1;min-width:10px;background:linear-gradient(var(--brand2),var(--brand));border-radius:5px 5px 0 0}.focus-demo:focus,.button:focus,.nav:focus,input:focus,select:focus,textarea:focus{outline:3px solid #f4b942;outline-offset:2px}
html,body{overflow-x:visible}
@media(max-width:1000px){.shell{grid-template-columns:76px minmax(0,1fr)}aside{padding:20px 10px}.brand span,.nav span:last-child{display:none}.nav{justify-content:center}.cols-4{grid-template-columns:repeat(2,1fr)}.split{grid-template-columns:1fr}.action-panel{position:static}.life{grid-template-columns:repeat(4,1fr)}.content{padding:20px}}
@media(max-width:600px){.shell{display:block}aside{display:none}.top{height:auto;padding:12px 14px;flex-wrap:wrap}.avatar{display:none}.global-create{margin-left:auto;max-width:45%}.search{order:3;width:100%;max-width:100%;flex:1 0 100%}.content{padding:14px}.page-head,.case-title{align-items:start;flex-direction:column}.page-head h1{font-size:23px}.cols-4,.cols-3,.cols-2,.form-grid{grid-template-columns:1fr}.workspace-head{position:static}.life{grid-template-columns:repeat(2,minmax(0,1fr))}.stepper{grid-template-columns:1fr}.step{text-align:left}.review{grid-template-columns:1fr}.review dd{margin-bottom:8px}.hide-mobile{display:none}}
</style></head><body data-page="$(E $pageId)" data-state="$(E $State)"><a class="skip" href="#content">Skip to content</a><div class="shell"><aside aria-label="Primary navigation"><div class="brand"><div class="brand-mark">C</div><span>Case Hub</span></div>$navigation</aside><main class="main"><header class="top"><input class="search" aria-label="Global case search" placeholder="Search case, party or reference…">$primaryButton<div class="avatar" aria-label="Signed in as Alex Morgan">AM</div></header><div class="content" id="content">$body</div></main></div><script>addEventListener('load',()=>{const b=document.body,p=b.dataset.page,s=b.dataset.state;if(s==='read-only'&&p==='case-workspace'){const a=document.querySelector('.action-panel');a.querySelectorAll('.button').forEach(x=>x.remove());a.insertAdjacentHTML('beforeend','<div class="callout"><b>Read-only access.</b> You can review this case but cannot perform lifecycle actions.</div>')}if(s==='long-content'&&p==='case-workspace'){document.querySelector('.case-title h1').textContent='Seal integrity failure detected during extended incoming pressure and thermal-cycle validation';document.querySelector('.grid article p').textContent='Incoming valve lot NV-8842 failed repeated pressure and thermal-cycle validation at the primary seal interface. The full lot remains quarantined while supplier engineering completes material analysis and provides traceability evidence.'}if(s==='empty'&&p==='my-work'){document.querySelectorAll('.table-wrap,.timeline').forEach(x=>x.outerHTML='<div class="empty">You have no open work in this view.</div>')}b.dataset.clientWidth=document.documentElement.clientWidth;b.dataset.scrollWidth=document.documentElement.scrollWidth;b.dataset.horizontalOverflow=document.documentElement.scrollWidth>document.documentElement.clientWidth?'true':'false'})</script></body></html>
"@
}
function DashboardBody([string]$title){
    $rows=if($State -eq 'empty'){"<div class='empty'>No urgent work matches the current filters.</div>"}else{"<div class='table-wrap'><table><caption class='skip'>Urgent cases</caption><thead><tr><th>Case</th><th>Stage</th><th>Owner</th><th>Risk</th><th>SLA</th></tr></thead><tbody><tr><td><b>SNC-2026-0142</b><br>Seal failure on incoming valve</td><td>Investigate</td><td>A. Khan</td><td>$(Status 'High' 'critical')</td><td>$(Status 'Breached 2d' 'critical')</td></tr><tr><td><b>SNC-2026-0137</b><br>Incorrect coating thickness</td><td>Decide</td><td>L. Morgan</td><td>$(Status 'Medium' 'warning')</td><td>$(Status 'Due today' 'warning')</td></tr></tbody></table></div>"}
"<section class='page-head'><div><h1>$(E $title)</h1><p>Live operational position · updated 2 minutes ago</p></div><div class='toolbar'><button class='button'>All sites ▾</button><button class='button'>Last 90 days ▾</button></div></section><section class='grid cols-4'><article class='card kpi'><label>Open cases</label><div class='value'>47</div></article><article class='card kpi'><label>SLA at risk</label><div class='value'>8</div></article><article class='card kpi'><label>Overdue actions</label><div class='value'>12</div></article><article class='card kpi'><label>High-risk cases</label><div class='value'>5</div></article></section><section class='grid cols-2' style='margin-top:15px'><article class='card pad'><h2>Open cases by stage</h2><div class='chart-bars' role='img' aria-label='Open cases by stage: Capture 7, Investigate 18, Decide 10, Resolve 8'><i style='height:38%'></i><i style='height:88%'></i><i style='height:55%'></i><i style='height:46%'></i></div><a href='#stage-table'>View data table</a></article><article class='card pad'><h2>Case intake trend</h2><div class='chart-bars' role='img' aria-label='Monthly case intake trend'><i style='height:52%'></i><i style='height:64%'></i><i style='height:46%'></i><i style='height:78%'></i><i style='height:58%'></i></div><a href='#trend-table'>View data table</a></article></section><section class='card' style='margin-top:15px'><div class='card-head'><div><h2>Urgent work</h2><span class='muted'>Cases requiring intervention</span></div><a class='button' href='case-search.html'>View all</a></div>$rows</section>"
}
function WorkBody([string]$title){
"<section class='page-head'><div><h1>$(E $title)</h1><p>Your allocated work, owned cases, and recent activity</p></div></section><section class='grid cols-3'><article class='card kpi'><label>Open tasks</label><div class='value'>6</div></article><article class='card kpi'><label>Due in 7 days</label><div class='value'>3</div></article><article class='card kpi'><label>Cases I own</label><div class='value'>11</div></article></section><section class='grid cols-2' style='margin-top:15px'><article class='card'><div class='card-head'><h2>My open tasks</h2><button class='button'>Filter</button></div><div class='table-wrap'><table><caption class='skip'>My open tasks</caption><thead><tr><th>Task</th><th>Case</th><th>Due</th></tr></thead><tbody><tr><td><b>Review containment</b></td><td>SNC-2026-0142</td><td>$(Status 'Today' 'warning')</td></tr><tr><td><b>Approve disposition</b></td><td>SNC-2026-0137</td><td>Tomorrow</td></tr></tbody></table></div></article><article class='card pad'><h2>Recent activity</h2><ol class='timeline'><li><b>Evidence verified</b><time>12 minutes ago · SNC-2026-0142</time>Supplier certificate approved by A. Khan.</li><li><b>Case moved to Decide</b><time>Yesterday · SNC-2026-0137</time>Investigation completed.</li><li><b>Corrective action assigned</b><time>Monday · SNC-2026-0129</time>Assigned to R. Singh.</li></ol></article></section>"
}
function InitiationBody([string]$title){
    $error=if($State -eq 'validation-error'){"<div class='callout error' role='alert'><b>We could not save this draft.</b> Complete the 2 highlighted fields and try again.</div>"}else{"<div class='callout'><b>Draft saved automatically.</b> You can leave and resume from Cases.</div>"}
    $invalid=if($State -eq 'validation-error'){' invalid'}else{''};$errorText=if($State -eq 'validation-error'){"<div class='error-text'>Enter a concise title.</div>"}else{''}
"<section class='page-head'><div><h1>$(E $title)</h1><p>Report an issue once; the case will guide investigation and resolution.</p></div><a class='button' href='case-search.html'>Save and exit</a></section>$error<section class='card pad' style='margin-top:14px'><div class='stepper' aria-label='Initiation progress'><div class='step done'>1 What happened?</div><div class='step done'>2 Context</div><div class='step done'>3 Impact</div><div class='step done'>4 Evidence</div><div class='step current' aria-current='step'>5 Review</div></div><h2>Review and submit</h2><p class='muted'>Confirm the details below. Submission starts the governed case lifecycle.</p><div class='form-grid'><div class='field'><label class='required' for='case-title'>Title</label><input id='case-title' class='$invalid' value='Seal failure on incoming valve' aria-invalid='$($State -eq 'validation-error')'>$errorText</div><div class='field'><label for='supplier'>Supplier</label><input id='supplier' value='Northstar Components'></div><div class='field'><label for='severity'>Severity</label><select id='severity'><option>Major</option></select></div><div class='field'><label for='target'>Target resolution</label><input id='target' type='date' value='2026-07-29'></div></div><dl class='review' style='margin-top:20px'><dt>Description</dt><dd>Incoming valve lot failed pressure testing at the seal interface.</dd><dt>Containment</dt><dd>Lot quarantined; receiving inspection increased to 100%.</dd><dt>Evidence</dt><dd>3 attachments · certificate, test record, photographs</dd><dt>Risk</dt><dd>$(Status 'High' 'critical')</dd></dl><div class='actions' style='justify-content:flex-end;margin-top:20px'><button class='button'>Back</button><button class='button'>Save draft</button><button class='button primary'>Submit case</button></div></section>"
}
function WorkspaceBody([string]$title){
    $sla=if($State -eq 'sla-breached'){Status 'Breached by 2 days' 'critical'}else{Status 'At risk · 9h left' 'warning'}
"<section class='card workspace-head'><div class='case-title'><div><div class='eyebrow'>SNC-2026-0142 · Supplier nonconformance</div><h1>Seal failure on incoming valve</h1><div class='actions'>$(Status 'Open' 'info') $(Status 'High risk' 'critical') $sla</div></div><div class='actions'><button class='button'>Copy link</button><button class='button'>Export summary</button></div></div><div class='meta'><div><span class='muted'>Owner</span><b>A. Khan</b></div><div><span class='muted'>Current stage</span><b>Investigate</b></div><div><span class='muted'>Target</span><b>29 Jul 2026</b></div><div><span class='muted'>Supplier</span><b>Northstar Components</b></div></div><div class='life' aria-label='Case lifecycle'><div class='stage done'>Capture</div><div class='stage done'>Validate</div><div class='stage done'>Classify</div><div class='stage done'>Assign</div><div class='stage current' aria-current='step'>Investigate</div><div class='stage'>Decide</div><div class='stage'>Resolve</div><div class='stage'>Close</div></div></section><div class='split' style='margin-top:15px'><section class='card'><nav class='tabs' aria-label='Case sections'><a class='tab active' href='#overview'>Overview</a><a class='tab' href='#tasks'>Tasks</a><a class='tab' href='#evidence'>Evidence</a><a class='tab' href='#decisions'>Decisions</a><a class='tab' href='#actions'>Corrective actions</a><a class='tab' href='#history'>History</a></nav><div class='pad'><div class='callout'><b>Next best action:</b> Verify supplier evidence and complete the investigation task by today.</div><div class='grid cols-2' style='margin-top:16px'><article><h2>Case summary</h2><p>Valve lot NV-8842 failed pressure testing. The affected quantity is 240 units; all stock is quarantined.</p><dl class='review'><dt>Part</dt><dd>VL-440</dd><dt>Lot</dt><dd>NV-8842</dd><dt>Affected</dt><dd>240 units</dd><dt>Containment</dt><dd>Required and active</dd></dl></article><article><h2>Activity</h2><ol class='timeline'><li><b>Evidence added</b><time>12 minutes ago · A. Khan</time>Supplier certificate uploaded.</li><li><b>Investigation started</b><time>Yesterday · Workflow</time>Task allocated to Quality Engineering.</li><li><b>Containment confirmed</b><time>20 Jul · J. Adams</time>Warehouse quarantine confirmed.</li></ol></article></div></div></section><aside class='card pad action-panel'><h2>Available actions</h2><p class='muted'>Actions reflect your role and the current stage.</p><button class='button primary'>Complete investigation</button><button class='button'>Request information</button><button class='button'>Add evidence</button><button class='button'>Reassign</button><button class='button danger'>Place on hold</button><hr style='border:0;border-top:1px solid var(--line);margin:16px 0'><span class='muted'>All lifecycle changes are audited and may require a reason.</span></aside></div>"
}
function ReportsBody([string]$title){
"<section class='page-head'><div><h1>$(E $title)</h1><p>Governed operational, performance, compliance, and improvement reporting</p></div><button class='button'>Schedule delivery</button></section><section class='grid cols-3'><article class='card report'><div class='eyebrow'>Operations</div><h2>Backlog and aging</h2><p class='muted'>Open cases by stage, age bucket, owner, site, and SLA condition.</p><a href='#'>Run report →</a></article><article class='card report'><div class='eyebrow'>Performance</div><h2>Throughput and cycle time</h2><p class='muted'>Created, resolved, closed, median cycle time, and bottleneck stages.</p><a href='#'>Run report →</a></article><article class='card report'><div class='eyebrow'>Compliance</div><h2>SLA performance</h2><p class='muted'>Warnings, breaches, pauses, escalations, and business-delay attribution.</p><a href='#'>Run report →</a></article><article class='card report'><div class='eyebrow'>Quality</div><h2>Root cause and recurrence</h2><p class='muted'>Root-cause families, repeat suppliers/items, reopen and recurrence rates.</p><a href='#'>Run report →</a></article><article class='card report'><div class='eyebrow'>Actions</div><h2>CAPA effectiveness</h2><p class='muted'>Corrective actions by status, due performance, verification, and outcome.</p><a href='#'>Run report →</a></article><article class='card report'><div class='eyebrow'>Governance</div><h2>Decisions and overrides</h2><p class='muted'>Disposition, authority level, adverse decisions, overrides, and rationale.</p><a href='#'>Run report →</a></article></section><section class='card pad' style='margin-top:15px'><h2>Saved reports</h2><div class='table-wrap'><table><caption class='skip'>Saved reports</caption><thead><tr><th>Name</th><th>Owner</th><th>Schedule</th><th>Last run</th><th>Format</th></tr></thead><tbody><tr><td><b>Weekly quality operations</b></td><td>Quality Management</td><td>Monday 07:00</td><td>20 Jul 2026</td><td>PDF + Excel</td></tr><tr><td><b>Supplier monthly scorecard</b></td><td>Supplier Quality</td><td>Monthly</td><td>1 Jul 2026</td><td>Excel</td></tr></tbody></table></div></section>"
}
foreach($pageId in $Pages){
    $page=Page $pageId;if($null -eq $page){throw "Reference page '$pageId' is not declared in the UX manifest."}
    $body=switch($pageId){'operations-dashboard'{DashboardBody $page.title};'my-work'{WorkBody $page.title};'case-initiation'{InitiationBody $page.title};'case-workspace'{WorkspaceBody $page.title};'reports'{ReportsBody $page.title};default{throw "No reference renderer exists for page '$pageId'."}}
    $primary=if($pageId -eq 'case-initiation'){''}else{'New case'}
    $html=Shell $pageId $page.title $body $primary
    $path=Join-Path $destination ($pageId+'.html');[IO.File]::WriteAllText($path,$html,[Text.UTF8Encoding]::new($false));Write-Output "Rendered case UX reference: $path"
}
